using System; using System.Linq; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class UserRegistrationPage:Page { public UserRegistrationPage(){InitializeComponent();} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnRegister_Click(object s,RoutedEventArgs e){if(txtPassword.Password!=txtPasswordRepeat.Password||string.IsNullOrWhiteSpace(txtLogin.Text)){MessageBox.Show("Проверьте логин и пароль");return;} if(AppConnect.model01.Users.Any(x=>x.Login==txtLogin.Text.Trim())){MessageBox.Show("Логин занят");return;} var role=AppConnect.model01.UserRoles.First(x=>x.RoleName=="Менеджер"); var u=new Users{FullName=txtName.Text.Trim(),Login=txtLogin.Text.Trim(),Password=txtPassword.Password,Email=txtEmail.Text.Trim(),Phone=txtPhone.Text.Trim(),RoleID=role.RoleID,CreatedAt=DateTime.Now,IsBlocked=false}; AppConnect.model01.Users.Add(u); AppConnect.model01.SaveChanges(); MessageBox.Show("Пользователь создан"); AppFrame.frmMain.GoBack();}}}
